sql:
SELECT cycle_id, total_failures_in_cycle
FROM test_cycles
ORDER BY total_failures_in_cycle DESC;

SELECT cycle_id, AVG(exec_time) AS avg_exec_time
FROM test_cycles
GROUP BY cycle_id;

SELECT AVG(avg_response_time) AS average_response_time, MAX(peak_memory_usage) AS max_memory_usage
FROM test_cycle_metrics
WHERE cycle_id = '0';

SELECT cycle_id
FROM test_cycles
WHERE total_failures_in_cycle > 0;

SELECT cycle_id
FROM test_cycles
WHERE total_failures_in_cycle = (
    SELECT MIN(total_failures_in_cycle)
    FROM test_cycles
);

SELECT COUNT(*) AS total_test_cycles
FROM test_cycles
WHERE environment_id = 1;

SELECT cycle_id 
FROM test_cycles 
ORDER BY cycle_id;

SELECT cycle_id
FROM test_cycles
WHERE exec_time = (SELECT MAX(exec_time) FROM test_cycles);

external_knowledge:
; test cycles are a series of test executions that may be organized hierarchically, potentially representing different phases or stages of testing; 
; the identifiers (cycle_id) uniquely represent each test cycle within the database;
; the inclusion of hierarchical levels, performance metrics, user accesses, environment settings, and test suites provides a comprehensive view of each cycle.

sql:
SELECT cycle_id
FROM test_cycles
ORDER BY cycle_id;

external_knowledge:
- The top 3 cycles refer to the cycles with the highest normalized RPA, indicating the best performance; 
- Normalized RPA is a performance index that indicates how well a test cycle has performed, with higher values generally indicating better performance;
- Execution time at the 50th percentile refers to the execution time below which 50% of the test cycles fall, providing a measure of central tendency that is less affected by outliers than the mean.
